final:
module gray_code_counter_4bit (
    input wire clk,
    input wire rst,
    output reg [3:0] gray
    );

reg [3:0] binary_count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) begin
        binary_count <= 4'b0000;
    end else begin
        binary_count <= binary_count + 1;
    end
end

always @(*) begin
    gray = (binary_count >> 1) ^ binary_count;
end

endmodule
